<?php
session_start(); require 'db_connection.php'; require_once 'helpers.php'; require_admin(); $conn=OpenCon(); $id=(int)($_GET['id']??0);
$stmt=$conn->prepare("SELECT * FROM tickets WHERE id=?"); $stmt->bind_param("i",$id); $stmt->execute(); $ticket=$stmt->get_result()->fetch_assoc(); if(!$ticket) die('Ticket not found');
if(isset($_POST['reply']) && $ticket['status']==='open'){ $msg=trim($_POST['message']); if($msg!==''){ $sender='admin'; $ins=$conn->prepare("INSERT INTO ticket_messages (ticket_id,sender,message) VALUES (?,?,?)"); $ins->bind_param("iss",$id,$sender,$msg); $ins->execute(); $u=$conn->prepare("SELECT email FROM users WHERE id=?"); $u->bind_param("i",$ticket['user_id']); $u->execute(); $user=$u->get_result()->fetch_assoc(); if($user) send_html_mail($user['email'],'Reply to your support request','<p>You have a new admin reply in your ticket.</p>'); } redirect("admin_ticket_view.php?id=$id"); }
if(isset($_POST['close'])){ $upd=$conn->prepare("UPDATE tickets SET status='closed', closed_at=NOW() WHERE id=?"); $upd->bind_param("i",$id); $upd->execute(); $hist=$conn->prepare("INSERT INTO contact_history (ticket_id,user_id,closed_at) VALUES (?,?,NOW())"); $hist->bind_param("ii",$id,$ticket['user_id']); $hist->execute(); redirect('admin_tickets.php'); }
$msgs=$conn->prepare("SELECT * FROM ticket_messages WHERE ticket_id=? ORDER BY created_at"); $msgs->bind_param("i",$id); $msgs->execute(); $messages=$msgs->get_result();
?>
<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Ticket</title><link rel="stylesheet" href="css/style.css"></head><body><?php include 'navbar.php'; ?><div class="admin-container"><h2>Ticket #<?=$id?></h2><div class="card"><?php while($m=$messages->fetch_assoc()):?><p><b>[<?=e($m['created_at'])?>] <?=e($m['sender'])?>:</b> <?=e($m['message'])?></p><?php endwhile;?></div><?php if($ticket['status']==='open'):?><form method="post" class="card"><textarea name="message" rows="4" required></textarea><button name="reply">Reply</button> <button name="close" class="danger">Close Ticket</button></form><?php else:?><p class="error">This ticket is closed.</p><?php endif;?></div></body></html>
